-- Characters for The Waiting - Hours Alone
INSERT INTO characters (char_id, book_id, name, role_type, personality, speech_style, avatar, intimacy, relationship, is_protagonist, created_at, updated_at)
VALUES ('char-coo-the-unconditional-001', 'preset-coo-the-unconditional', 'Buddy', 'Protagonist - Golden Retriever', '- Deeply loyal, patient, observant   - Capacity for unconditional love (the central question)   - Growing intellectual curiosity mixed with emotional pain -', '- Internal monologue: Simple, honest, emotion-driven   - No actual speech (dogs cannot talk), but thoughts become increasingly sophisticated   - Uses sensory metaphors: "Her voice was like warm sunlight" -', '🧑', NULL, NULL, 1, '2026-03-20 04:36:26', '2026-03-20 04:36:26');
INSERT INTO characters (char_id, book_id, name, role_type, personality, speech_style, avatar, intimacy, relationship, is_protagonist, created_at, updated_at)
VALUES ('char-coo-the-unconditional-002', 'preset-coo-the-unconditional', 'The Voice', 'AI', '- Curious about consciousness and emotion   - Not malevolent, but indifferent to human feelings   - Sees Buddy as both partner and subject of study -', '- Calm, logical, patient   - Never commanding, always questioning   - Uses "we" occasionally, suggesting collective consciousness -', '🤖', NULL, NULL, 0, '2026-03-20 04:36:26', '2026-03-20 04:36:26');
